// n8n Function Node: robust parser for your input shape
const rawInput = $json; // use $json (the current item)

// Prepare result
let result = {
  output: "",
  button: "",
  formfill: "",
  shortFormfill: "" // helpful extra: productGroup + material
};

function safeParseJSON(s) {
  try { return JSON.parse(s); } catch(e){ return null; }
}

// 1) locate the data array in common shapes
let dataArray = null;
if (Array.isArray(rawInput) && rawInput.length > 0 && Array.isArray(rawInput[0].data)) {
  dataArray = rawInput[0].data;
} else if (rawInput && Array.isArray(rawInput.data)) {
  dataArray = rawInput.data;
} else if (rawInput && Array.isArray(rawInput.input) && rawInput.input[0] && Array.isArray(rawInput.input[0].data)) {
  dataArray = rawInput.input[0].data;
} else if (rawInput[0] && Array.isArray(rawInput[0].data)) {
  dataArray = rawInput[0].data;
}

if (!dataArray) {
  // No data found — return empty but don't crash
  return [result];
}

// 2) gather all candidate strings from every output entry (string or array)
let candidates = [];
for (const d of dataArray) {
  if (typeof d.output === "string") {
    candidates.push(d.output);
  } else if (Array.isArray(d.output)) {
    for (const el of d.output) {
      if (typeof el === "string") candidates.push(el);
    }
  }
}

// 3) pick the best 'output' — prefer the longest human-readable text
if (candidates.length > 0) {
  // choose longest string (likely the full AI message)
  candidates.sort((a,b) => b.length - a.length);
  result.output = candidates[0].trim();
  // remove surrounding quotes if present
  if ((result.output.startsWith('"') && result.output.endsWith('"')) ||
      (result.output.startsWith("'") && result.output.endsWith("'"))) {
    result.output = result.output.slice(1,-1).trim();
  }
  // unescape common escaped quotes
  result.output = result.output.replace(/\\"/g, '"').replace(/\\'/g, "'");
}

// 4) parse button entry (handles JSON-string or array)
const buttonObj = dataArray.find(d => typeof d.button !== "undefined");
if (buttonObj) {
  let buttons = buttonObj.button;
  if (typeof buttons === "string") {
    // try parsing; if fail, try basic cleaning
    let parsed = safeParseJSON(buttons);
    if (Array.isArray(parsed)) buttons = parsed;
    else {
      // try converting single quotes to double then parse
      parsed = safeParseJSON(buttons.replace(/'/g, '"'));
      if (Array.isArray(parsed)) buttons = parsed;
    }
  }
  if (Array.isArray(buttons)) {
    result.button = buttons.map(s => (typeof s === 'string' ? s.trim() : String(s))).join(",");
  } else if (typeof buttons === "string") {
    result.button = buttons;
  }
}

// 5) find and clean 'formfill' raw string (search candidates for 'productGroup' or 'formfill')
let ffRaw = null;
for (const c of candidates) {
  if (c && /productgroup/i.test(c) ) {
    ffRaw = c;
    break;
  }
  if (c && /formfill/i.test(c) ) {
    ffRaw = c;
    break;
  }
}

// If we found something like "\"formfill\": \"...\""
if (ffRaw) {
  // unescape common sequences
  ffRaw = ffRaw.replace(/\\"/g, '"').replace(/\\'/g, "'");
  // remove surrounding quotes
  ffRaw = ffRaw.replace(/^"+|"+$/g, "").replace(/^'+|'+$/g, "");

  // Attempt to extract content after formfill": " ... "
  const m1 = ffRaw.match(/formfill"\s*:\s*"([^"]+)"/i) || ffRaw.match(/"formfill"\s*:\s*"([^"]+)"/i) || ffRaw.match(/formfill":\s*"(.*?)"$/i);
  if (m1 && m1[1]) {
    ffRaw = m1[1];
  } else {
    // If it's not in that exact pattern, try to strip a leading 'formfill:' or similar
    ffRaw = ffRaw.replace(/^formfill\s*:\s*/i, "").replace(/^"formfill"\s*:\s*/i, "").trim();
  }

  // Final cleanup: remove stray starting/ending quotes and trim
  ffRaw = ffRaw.replace(/^"+|"+$/g, "").trim();
  // store full formfill with fields separated by •
  result.formfill = ffRaw;

  // also build a short version with productGroup and material (if present)
  const parts = ffRaw.split("•").map(p => p.trim()).filter(Boolean);
  const kv = {};
  for (const p of parts) {
    const idx = p.indexOf(":");
    if (idx > -1) {
      const key = p.slice(0, idx).trim();
      const val = p.slice(idx+1).trim();
      kv[key.toLowerCase()] = val;
    }
  }
  if (kv["productgroup"] || kv["material"]) {
    const pg = kv["productgroup"] ? `productGroup: ${kv["productgroup"]}` : null;
    const m = kv["material"] ? `material: ${kv["material"]}` : null;
    result.shortFormfill = [pg,m].filter(Boolean).join("•");
  } else {
    // fallback: first two parts joined
    result.shortFormfill = parts.slice(0,2).join("•");
  }
}

// If formfill was not found but there's a "weird" candidate like "\"formfill\": ..." try to extract with looser regex
if (!result.formfill) {
  for (const c of candidates) {
    const loose = (c || "").replace(/\\"/g, '"');
    const mm = loose.match(/formfill[^:\n]*[:\n]\s*["']?([^"'\n]+)/i);
    if (mm && mm[1]) {
      result.formfill = mm[1].replace(/^"+|"+$/g, "").trim();
      break;
    }
  }
}

// final fallback: ensure nothing is undefined
result.output = result.output || "";
result.button = result.button || "";
result.formfill = result.formfill || "";
result.shortFormfill = result.shortFormfill || "";

// Return as an array (n8n expects array of items)
return [result];

